18	// IsRenderedConfigReconcilable checks the new rendered config against the old
19	// rendered config to make sure that the only changes requested are ones we
20	// know how to do in-place. If we can reconcile, (nil) is returned. Otherwise,
21	// if we can't do it in place, the returned string value includes the
22	// rationale.
23	//
24	// We can only update machine configs that have changes to the files,
25	// directories, links, and systemd units sections of the included ignition
26	// config currently.
27	func IsRenderedConfigReconcilable(oldConfig, newConfig *mcfgv1.MachineConfig,
28		overrides *opv1.IrreconcilableValidationOverrides) error {
29		return IsComponentConfigsReconcilable(oldConfig, []*mcfgv1.MachineConfig{newConfig}, overrides)
30	}
31	
32	// IsComponentConfigsReconcilable checks each individual component
33	// MachineConfig against the old rendered config. This is slightly more
34	// efficient because we only have to process the old config once. If an error
35	// occurs, the name of the component config will be included in the error
36	// message.
37	func IsComponentConfigsReconcilable(oldConfig *mcfgv1.MachineConfig,
38		newConfigs []*mcfgv1.MachineConfig,
39		overrides *opv1.IrreconcilableValidationOverrides,
40	) error {
41		// The parser will try to translate versions less than maxVersion to maxVersion, or output an err.
42		// The ignition output in case of success will always have maxVersion
43		oldIgn, err := ParseAndConvertConfig(oldConfig.Spec.Config.Raw)
44		if err != nil {
45			return fmt.Errorf("parsing old Ignition config from machineconfig %q failed: %w", oldConfig.Name, err)
46		}
47	
48		// Go through each component config and determine if it is reconcilable.
49		for _, newConfig := range newConfigs {
50			if err := isReconcilable(oldIgn, oldConfig, newConfig, overrides); err != nil {
51				return err
52			}
53		}
54	
55		return nil
56	}
