194	// Validates that changes to the Passwd section of the Ignition config are
195	// reconcilable.
196	func validatePasswdChanges(oldIgn, newIgn ign3types.Config) error {
197		if !reflect.DeepEqual(oldIgn.Passwd.Groups, newIgn.Passwd.Groups) {
198			return fmt.Errorf("ignition Passwd Groups section contains changes")
199		}
200	
201		if !reflect.DeepEqual(oldIgn.Passwd.Users, newIgn.Passwd.Users) {
202			// there is an update to Users, we must verify that it is ONLY making an acceptable
203			// change to the SSHAuthorizedKeys for the user "core"
204			for _, user := range newIgn.Passwd.Users {
205				if user.Name != constants.CoreUserName {
206					return fmt.Errorf("ignition passwd user section contains unsupported changes: non-core user")
207				}
208			}
209			// We don't want to panic if the "new" users is empty, and it's still reconcilable because the absence of a user here does not mean "remove the user from the system"
210			if len(newIgn.Passwd.Users) != 0 {
211				klog.Infof("user data to be verified before ssh update: %v", newIgn.Passwd.Users[len(newIgn.Passwd.Users)-1])
212				if err := verifyUserFields(newIgn.Passwd.Users[len(newIgn.Passwd.Users)-1]); err != nil {
213					return err
214				}
215			}
216		}
217	
218		return nil
219	}
