788			if outUser.Name != "core" {
789				return ignConfig, fmt.Errorf("unexpected user with name: %v. Only core user is supported", outUser.Name)
790			}
791			for i := len(users) - 2; i >= 0; i-- {
792				if users[i].Name != "core" {
793					return ignConfig, fmt.Errorf("unexpected user with name: %v. Only core user is supported", users[i].Name)
794				}
795				for j := range users[i].SSHAuthorizedKeys {
796					outUser.SSHAuthorizedKeys = append(outUser.SSHAuthorizedKeys, users[i].SSHAuthorizedKeys[j])
797				}
798			}
799			// Ensure SSH key uniqueness
800			ignConfig.Passwd.Users = []ign2types.PasswdUser{dedupePasswdUserSSHKeys(outUser)}
801		}
802	
803		// outFiles and outUnits should now have all duplication removed
804		ignConfig.Storage.Files = outFiles
805		ignConfig.Systemd.Units = outUnits
806	
807		return ignConfig, nil
808	}
