99	// Determines if a given config is reconcilable.
100	func isConfigReconcilable(oldIgn, newIgn ign3types.Config, oldConfig, newConfig *mcfgv1.MachineConfig, overrides *opv1.IrreconcilableValidationOverrides) error {
101		// Passwd section
102	
103		// we don't currently configure Groups in place. we don't configure Users except
104		// for setting/updating SSHAuthorizedKeys for the only allowed user "core".
105		// otherwise we can't fix it if something changed here.
106		if !reflect.DeepEqual(oldIgn.Passwd, newIgn.Passwd) {
107			if err := validatePasswdChanges(oldIgn, newIgn); err != nil {
108				return fmt.Errorf("invalid passwd change(s): %w", err)
109			}
110		}
111	
112		// Kernel args
113	
114		// ignition now supports kernel args, but the MCO doesn't implement them yet
115		if !reflect.DeepEqual(oldIgn.KernelArguments, newIgn.KernelArguments) {
116			return fmt.Errorf("ignition kargs section contains changes")
117		}
118	
119		// Storage section
120		var storageOverrides []opv1.IrreconcilableValidationOverridesStorage
121		if overrides != nil {
122			storageOverrides = overrides.Storage
123		}
124	
125		if !slices.Contains(storageOverrides, opv1.IrreconcilableValidationOverridesStorageDisks) &&
126			!reflect.DeepEqual(oldIgn.Storage.Disks, newIgn.Storage.Disks) {
127			return fmt.Errorf("ignition disks section contains changes")
128		}
129		if !slices.Contains(storageOverrides, opv1.IrreconcilableValidationOverridesStorageFileSystems) &&
130			!reflect.DeepEqual(oldIgn.Storage.Filesystems, newIgn.Storage.Filesystems) {
131			return fmt.Errorf("ignition filesystems section contains changes")
132		}
133		if !slices.Contains(storageOverrides, opv1.IrreconcilableValidationOverridesStorageRaid) &&
134			!reflect.DeepEqual(oldIgn.Storage.Raid, newIgn.Storage.Raid) {
135			return fmt.Errorf("ignition raid section contains changes")
136		}
137		if !reflect.DeepEqual(oldIgn.Storage.Directories, newIgn.Storage.Directories) {
138			return fmt.Errorf("ignition directories section contains changes")
139		}
140		if !reflect.DeepEqual(oldIgn.Storage.Links, newIgn.Storage.Links) {
141			// This means links have been added, as opposed as being removed as it happened with
142			// https://bugzilla.redhat.com/show_bug.cgi?id=1677198. This doesn't really change behavior
143			// since we still don't support links but we allow old MC to remove links when upgrading.
144			if len(newIgn.Storage.Links) != 0 {
145				return fmt.Errorf("ignition links section contains changes")
146			}
147		}
148	
149		// Special case files append: if the new config wants us to append, then we
150		// have to force a reprovision since it's not idempotent
151		for _, f := range newIgn.Storage.Files {
152			if len(f.Append) > 0 {
153				return fmt.Errorf("ignition file %v includes append", f.Path)
154			}
155			// We also disallow writing some special files
156			if f.Path == constants.MachineConfigDaemonForceFile {
157				return fmt.Errorf("cannot create %s via Ignition", f.Path)
158			}
159		}
160	
161		// FIPS section
162		// We do not allow update to FIPS for a running cluster, so any changes here will be an error.
163		// We do a naive check here for reusability. The MCD will continue to do a
164		// more in-depth check, taking the nodes filesystem into consideration.
165		if oldConfig.Spec.FIPS != newConfig.Spec.FIPS {
166			return fmt.Errorf("detected change to FIPS flag; refusing to modify FIPS on a running cluster")
167		}
168	
169		return nil
170	}
171	
172	// verifyUserFields returns nil for the user Name = "core" if 1 or more SSHKeys exist for
173	// this user or if a password exists for this user and if all other fields in User are empty.
174	// Otherwise, an error will be returned and the proposed config will not be reconcilable.
175	// At this time we do not support non-"core" users or any changes to the "core" user
176	// outside of SSHAuthorizedKeys and passwordHash.
177	func verifyUserFields(pwdUser ign3types.PasswdUser) error {
178		emptyUser := ign3types.PasswdUser{}
179		tempUser := pwdUser
180		if tempUser.Name == constants.CoreUserName && ((tempUser.PasswordHash) != nil || len(tempUser.SSHAuthorizedKeys) >= 1) {
181			tempUser.Name = ""
182			tempUser.SSHAuthorizedKeys = nil
183			tempUser.PasswordHash = nil
184			if !reflect.DeepEqual(emptyUser, tempUser) {
185				return fmt.Errorf("SSH keys and password hash are not reconcilable")
186			}
187			klog.Info("SSH Keys reconcilable")
188		} else {
189			return fmt.Errorf("ignition passwd user section contains unsupported changes: user must be core and have 1 or more sshKeys")
190		}
191		return nil
192	}
193	
194	// Validates that changes to the Passwd section of the Ignition config are
195	// reconcilable.
196	func validatePasswdChanges(oldIgn, newIgn ign3types.Config) error {
197		if !reflect.DeepEqual(oldIgn.Passwd.Groups, newIgn.Passwd.Groups) {
198			return fmt.Errorf("ignition Passwd Groups section contains changes")
199		}
200	
201		if !reflect.DeepEqual(oldIgn.Passwd.Users, newIgn.Passwd.Users) {
202			// there is an update to Users, we must verify that it is ONLY making an acceptable
203			// change to the SSHAuthorizedKeys for the user "core"
204			for _, user := range newIgn.Passwd.Users {
205				if user.Name != constants.CoreUserName {
206					return fmt.Errorf("ignition passwd user section contains unsupported changes: non-core user")
207				}
208			}
209			// We don't want to panic if the "new" users is empty, and it's still reconcilable because the absence of a user here does not mean "remove the user from the system"
210			if len(newIgn.Passwd.Users) != 0 {
211				klog.Infof("user data to be verified before ssh update: %v", newIgn.Passwd.Users[len(newIgn.Passwd.Users)-1])
212				if err := verifyUserFields(newIgn.Passwd.Users[len(newIgn.Passwd.Users)-1]); err != nil {
213					return err
214				}
215			}
216		}
217	
218		return nil
219	}
