301	// the RawExtension is spec v3.5, or translates to it.
302	func ConvertRawExtIgnitionToV3_5(inRawExtIgn *runtime.RawExtension) (runtime.RawExtension, error) {
303		// Parse the raw extension to the MCO's current internal ignition version
304		ignCfgV3, err := IgnParseWrapper(inRawExtIgn.Raw)
305		if err != nil {
306			return runtime.RawExtension{}, err
307		}
308	
