113	// getJSONNodeFromMC transforms the given mcfgv1.MachineConfig into a jd.JsonNode
114	// that can be compared later.
115	// This function takes care of removing  reconcilable changes before the JSON conversion.
116	func getJSONNodeFromMC(mc *mcfgv1.MachineConfig) (jd.JsonNode, error) {
117		content, err := patchDaemonManagedFields(mc)
118		if err != nil {
119			return nil, fmt.Errorf("failed to patch MachineConfig for diff computing: %w", err)
120		}
121		node, err := jd.ReadJsonString(string(content))
122		if err != nil {
123			return nil, fmt.Errorf("failed to parse the MachineConfig as json: %w", err)
124		}
125		return node, nil
126	}
