128	// removeFirstAtLineExplicit removes all the lines of the given string till a line starting with '@' is found.
129	// The line that starts with '@' is removed too.
130	func removeFirstAtLineExplicit(rendered string) string {
131		lines := strings.Split(rendered, "\n")
132		for i, line := range lines {
133			if strings.HasPrefix(strings.TrimSpace(line), "@") {
134				return strings.Join(lines[i+1:], "\n")
135			}
136		}
137		return rendered
138	}
