140	// patchDaemonManagedFields removes from the given targetMachineConfig all the fields
141	// that the MCD handles to leave on it only what we consider irreconcilable and allow
142	// further comparison.
143	func patchDaemonManagedFields(targetMachineConfig *mcfgv1.MachineConfig) ([]byte, error) {
144		ignConfig, err := ctrlcommon.ParseAndConvertConfig(targetMachineConfig.Spec.Config.Raw)
145		if err != nil {
146			return nil, err
147		}
148		ign := ctrlcommon.NewIgnConfig()
149		ign.Storage.Disks = ignConfig.Storage.Disks
150		ign.Storage.Raid = ignConfig.Storage.Raid
151		ign.Storage.Filesystems = ignConfig.Storage.Filesystems
152		ign.Storage.Luks = ignConfig.Storage.Luks
153	
154		rawConf, err := json.Marshal(ign)
155		if err != nil {
156			return nil, err
157		}
158		config := mcfgv1.MachineConfig{Spec: mcfgv1.MachineConfigSpec{Config: runtime.RawExtension{Raw: rawConf}}}
159		return json.Marshal(config)
160	}
