164	// irreconcilableDifferencesReportGeneratorImpl.installTimeParamsPaths.
165	func (i *irreconcilableDifferencesReportGeneratorImpl) fetchBaseInstallTimeMachineConfig() *mcfgv1.MachineConfig {
166		for _, path := range i.installTimeParamsPaths {
