33	func (cfg Config) Validate(c path.ContextPath) (r report.Report) {
34		systemdPath := "/etc/systemd/system/"
35		unitPaths := map[string]struct{}{}
36		for _, unit := range cfg.Systemd.Units {
37			if !util.NilOrEmpty(unit.Contents) {
38				pathString := systemdPath + unit.Name
39				unitPaths[pathString] = struct{}{}
40			}
41			for _, dropin := range unit.Dropins {
42				if !util.NilOrEmpty(dropin.Contents) {
43					pathString := systemdPath + unit.Name + ".d/" + dropin.Name
44					unitPaths[pathString] = struct{}{}
45				}
46			}
47		}
48		for i, f := range cfg.Storage.Files {
49			if _, exists := unitPaths[f.Path]; exists {
50				r.AddOnError(c.Append("storage", "files", i, "path"), errors.ErrPathConflictsSystemd)
51			}
52		}
53		for i, d := range cfg.Storage.Directories {
54			if _, exists := unitPaths[d.Path]; exists {
55				r.AddOnError(c.Append("storage", "directories", i, "path"), errors.ErrPathConflictsSystemd)
56			}
57		}
58		for i, l := range cfg.Storage.Links {
59			if _, exists := unitPaths[l.Path]; exists {
60				r.AddOnError(c.Append("storage", "links", i, "path"), errors.ErrPathConflictsSystemd)
61			}
62		}
63		return
64	}
