36	func (f Filesystem) Validate(c path.ContextPath) (r report.Report) {
37		r.AddOnError(c.Append("path"), f.validatePath())
38		r.AddOnError(c.Append("device"), validatePath(f.Device))
39		r.AddOnError(c.Append("format"), f.validateFormat())
40		r.AddOnError(c.Append("label"), f.validateLabel())
41		return
42	}
43	
44	func (f Filesystem) validatePath() error {
45		return validatePathNilOK(f.Path)
46	}
47	
48	func (f Filesystem) validateFormat() error {
49		if util.NilOrEmpty(f.Format) {
50			if util.NotEmpty(f.Path) ||
51				util.NotEmpty(f.Label) ||
52				util.NotEmpty(f.UUID) ||
53				util.IsTrue(f.WipeFilesystem) ||
54				len(f.MountOptions) != 0 ||
55				len(f.Options) != 0 {
56				return errors.ErrFormatNilWithOthers
57			}
58		} else {
59			switch *f.Format {
60			case "ext4", "btrfs", "xfs", "swap", "vfat", "none":
61			default:
62				return errors.ErrFilesystemInvalidFormat
63			}
64		}
65		return nil
66	}
67	
68	func (f Filesystem) validateLabel() error {
69		if util.NilOrEmpty(f.Label) {
70			return nil
71		}
72		if util.NilOrEmpty(f.Format) {
73			return errors.ErrLabelNeedsFormat
74		}
75	
76		switch *f.Format {
77		case "ext4":
78			if len(*f.Label) > 16 {
79				// source: man mkfs.ext4
80				return errors.ErrExt4LabelTooLong
81			}
82		case "btrfs":
83			if len(*f.Label) > 256 {
84				// source: man mkfs.btrfs
85				return errors.ErrBtrfsLabelTooLong
86			}
87		case "xfs":
88			if len(*f.Label) > 12 {
89				// source: man mkfs.xfs
90				return errors.ErrXfsLabelTooLong
91			}
92		case "swap":
93			// mkswap's man page does not state a limit on label size, but through
94			// experimentation it appears that mkswap will truncate long labels to
95			// 15 characters, so let's enforce that.
96			if len(*f.Label) > 15 {
97				return errors.ErrSwapLabelTooLong
98			}
99		case "vfat":
100			if len(*f.Label) > 11 {
101				// source: man mkfs.fat
102				return errors.ErrVfatLabelTooLong
103			}
104		}
105		return nil
106	}
